def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        bonus = 0
        complexity = 1
        for j in range(1, 10):
            threshold = j * 0.1
            if ratio < threshold:
                increment = (10 - j) * np.log1p(capacity) * (1 + np.sin(j * 0.5)) * complexity
                score += increment
                if j % 3 == 0:
                    bonus += np.sqrt(capacity) / (j + 2) * np.cos(j)
                elif j % 2 == 0:
                    bonus += np.log1p(item) / (j + 1) * np.sin(j)
                else:
                    bonus += np.exp(-j / 10) * np.sqrt(item)
                complexity *= 1.05
            else:
                decrement = j * np.sqrt(item) * (1 + np.cos(j * 0.7)) * complexity
                penalty += decrement
                complexity /= 1.03
        if capacity < item * 1.1:
            score *= 2.0
            penalty *= 1.5
        elif capacity < item * 1.5:
            score *= 1.5
            penalty *= 1.2
        elif capacity > item * 5:
            score /= 3.0
            penalty /= 2.0
        elif capacity > item * 3.5:
            score /= 2.0
            penalty /= 1.5
        if 0.7 < ratio < 0.95:
            for k in range(5):
                score += (np.log1p(capacity) / (k + 1)) * np.sin(k + 1) - (np.sqrt(item) * (k + 1) * np.cos(k))
        if score < penalty:
            score = (penalty - score) * 0.75
        else:
            score = score - penalty
        if score < 0:
            score = np.abs(score) / 3
        if capacity % 2 == 0:
            score *= 1.1
        else:
            score *= 0.9
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 20
    return priorities
